// --- Watch Registration ---

// RegisterClassicladderWatch registers WebSocket watch functions and commands.
func RegisterClassicladderWatch(wreg *apiserver.WatchRegistry, instance string, watchImpl ClassicladderWatchCallbacks, commands []apiserver.CommandMeta) {
	wreg.Register(&apiserver.WatchAPI{
		APIName:  "classicladder",
		Instance: instance,
		Watches: []apiserver.WatchFuncMeta{
			{Name: "watch_status", DefaultRate: 100 * time.Millisecond, Watch: func() (json.RawMessage, error) {
				result, err := watchImpl.WatchStatus()
				if err != nil { return nil, err }
				return json.Marshal(result)
			}},
			{Name: "watch_variables", DefaultRate: 200 * time.Millisecond, Watch: func() (json.RawMessage, error) {
				result, err := watchImpl.WatchVariables()
				if err != nil { return nil, err }
				return json.Marshal(result)
			}},
		},
		Commands: commands,
	})
}
